-- Using the NYC Taxi public dataset (Yellow Trips) from Google BigQuery, complete the following exercises:



-- Exercise 1: Count the number of trips in January 2022
-- 2463900
SELECT
  COUNT(*) AS total_trips_jan_2022
FROM
  `bigquery-public-data.new_york_taxi_trips.tlc_yellow_trips_2022`
WHERE
  pickup_datetime >= '2022-01-01'
  AND pickup_datetime < '2022-02-01';



-- Exercise 2: Calculate the total revenue generated by taxi trips in 2022
-- 775917388.36
SELECT
  SUM(total_amount) AS total_revenue_2022
FROM
  `bigquery-public-data.new_york_taxi_trips.tlc_yellow_trips_2022`
WHERE
  pickup_datetime >= '2022-01-01'
  AND pickup_datetime < '2023-01-01';

-- Exercise 3: Find the most popular pickup location
-- 132
SELECT
  pickup_location_id,
  COUNT(*) AS trip_count
FROM
  `bigquery-public-data.new_york_taxi_trips.tlc_yellow_trips_2022`
GROUP BY
  pickup_location_id
ORDER BY
  trip_count DESC
LIMIT 1;

-- Exercise 4: Analyze the number of trips per hour of the day
SELECT
  EXTRACT(HOUR FROM pickup_datetime) AS pickup_hour,
  COUNT(*) AS trip_count
FROM
  `bigquery-public-data.new_york_taxi_trips.tlc_yellow_trips_2022`
GROUP BY
  pickup_hour
ORDER BY
  pickup_hour;

