-- Exercise 5: Calculate the average trip distance
-- 6.077670271
SELECT
  AVG(trip_distance) AS avg_trip_distance
FROM
  `bigquery-public-data.new_york_taxi_trips.tlc_yellow_trips_2022`;

-- Exercise 6: Find the longest trip by distance
SELECT
  trip_distance,
  pickup_datetime,
  dropoff_datetime  
FROM
  `bigquery-public-data.new_york_taxi_trips.tlc_yellow_trips_2022`
ORDER BY
  trip_distance DESC
LIMIT 1;

